import React from "react";
import UserDashboard from "../components/user/UserDashboard";

export default function UserPortal() {
  return (
    <div className="page">
      <h1>User Portal</h1>
      <p className="muted">
        View your decentralized KYC credential, level, and expiry, and use
        KYC-gated services without repeating checks.
      </p>
      <div className="grid">
        <UserDashboard />
      </div>
    </div>
  );
}
